using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e6+5;
int f[MAXN];
int fd(int x)
{
    if(f[x]!=x)
    {
        f[x]=fd(f[x]);
    }
    return f[x];
}

void un(int x,int y)
{
    x=fd(x);
    y=fd(y);
    f[y]=x;
}

signed main(void)
{
    int n,m,k,x,y,e=0;
    n=read();
    m=read();
    k=read();
    FOR(i,1,n*m)
    {
        f[i]=i;
    }
    FOR(i,1,k)
    {
        x=read();
        y=read();
        un(x,y);
    }
    FOR(i,1,n*m)
    {
        fd(i);
        if(f[i]==i)
        {
            e++;
        }
    }
    writeln(e);
    return false;
}
